#include <stdio.h>

int main()
{
	int n = 3, razmak = 1, broj_rijeci = 0;
	char tekst[] = "Ovo je neki primjer";
	char* s = tekst;
	char* pocetak = NULL;
	if (n <= 0) {
	    printf("Nevalidno n.");
	    return 1;
	}
	while (*s != '\0') {
		if (*s == ' ')
			razmak = 1;
		else if (razmak == 1) {
			razmak = 0;
			broj_rijeci++;
			if (broj_rijeci == n) pocetak = s;
			if (broj_rijeci == n+1) {
				while (*pocetak++ = *s++);
				break;
			}
		}
		s++;
	}
	if (broj_rijeci == n) *pocetak = '\0';

    printf("%s", tekst);
	return 0;
}
